2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Edge case: empty
6	  it("empty item list yields premium of 5 G (processing fee only)", () => {
7	    const result = processScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // Base premiums per item type
15	  it("quote for a single plain sword yields 105 G (100 base + 5 fee)", () => {
16	    const result = processScenario({
17	      customer: { yearsWithMHPCO: 5 },
18	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	    });
20	    expect(result).toEqual({ results: [{ premium: 105 }] });
21	  });
22	  it("quote for a single plain amulet yields 65 G (60 base + 5 fee)", () => {
23	    const result = processScenario({
24	      customer: { yearsWithMHPCO: 5 },
25	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
26	    });
27	    expect(result).toEqual({ results: [{ premium: 65 }] });
28	  });
29	  it("quote for a single plain staff yields 85 G (80 base + 5 fee)", () => {
30	    const result = processScenario({
31	      customer: { yearsWithMHPCO: 5 },
32	      steps: [{ op: "quote", items: [{ type: "staff" }] }],
33	    });
34	    expect(result).toEqual({ results: [{ premium: 85 }] });
35	  });
36	  it("quote for a single plain potion yields 45 G (40 base + 5 fee)", () => {
37	    const result = processScenario({
38	      customer: { yearsWithMHPCO: 5 },
39	      steps: [{ op: "quote", items: [{ type: "potion" }] }],
40	    });
41	    expect(result).toEqual({ results: [{ premium: 45 }] });
42	  });
43	
44	  // Components
45	  it("quote for a single rune yields 30 G (25 base + 5 fee)", () => {
46	    const result = processScenario({
47	      customer: { yearsWithMHPCO: 5 },
48	      steps: [{ op: "quote", items: [{ type: "rune" }] }],
49	    });
50	    expect(result).toEqual({ results: [{ premium: 30 }] });
51	  });
52	  it("quote for 2 runes yields 55 G (50 base + 5 fee)", () => {
53	    const result = processScenario({
54	      customer: { yearsWithMHPCO: 5 },
55	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
56	    });
57	    expect(result).toEqual({ results: [{ premium: 55 }] });
58	  });
59	  it("quote for 3 runes yields 65 G (block: 60 base + 5 fee)", () => {
60	    const result = processScenario({
61	      customer: { yearsWithMHPCO: 5 },
62	      steps: [
63	        {
64	          op: "quote",
65	          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
66	        },
67	      ],
68	    });
69	    expect(result).toEqual({ results: [{ premium: 65 }] });
70	  });
71	  it.todo("quote for 4 runes yields 105 G (100 base + 5 fee, no block)");
72	  it.todo("quote for 7 runes yields 180 G (175 base + 5 fee)");
73	
74	  // Alike components
75	  it.todo("quote for 2 runes + 1 moonstone yields 80 G (75 base + 5 fee, no block)");
76	  it.todo("quote for 3 runes + 3 moonstones yields 125 G (120 base + 5 fee, two blocks)");
77	
78	  // Item-specific modifiers
79	  it.todo("cursed sword adds 50% surcharge on item base premium");
80	  it.todo("sword with enchantment 5 adds 30% high-enchantment surcharge");
81	  it.todo("sword with enchantment 4 has no high-enchantment surcharge");
82	  it.todo("cursed sword with enchantment 5 gets both surcharges");
83	
84	  // Modifier scope on multi-item policy
85	  it.todo("policy with cursed sword + plain amulet: curse surcharge applies only to sword");
86	
87	  // Customer modifiers
88	  it.todo("customer with exactly 2 years gets 20% loyalty discount");
89	  it.todo("first insurance adds 10% surcharge per item");
90	  it.todo("follow-up contract gets 15% discount on policy");
91	
92	  // Rounding
93	  it.todo("premium that yields 197.5 G rounds UP to 198 G");
94	  it.todo("payout that yields 350.5 G rounds DOWN to 350 G");
95	
96	  // Integration examples
97	  it.todo("newcomer with cursed sword (steel, enchantment 3) → premium 165 G");
98	  it.todo("3-year customer's second quote with cursed sword (steel, enchantment 7) → premium 160 G");
99	
100	  // Claim: standard reimbursement
101	  it.todo("regular sword damage 500 G → payout 400 G (deductible)");
102	  it.todo("rune damage 200 G → payout 100 G (deductible)");
103	
104	  // Claim: special clauses
105	  it.todo("dragon-material sword enchantment 8 damage 1000 G → payout 400 G (50% then deductible)");
106	  it.todo("dragon-material sword enchantment 9 damage 1000 G → payout 400 G (50% wins)");
107	  it.todo("dragon-material sword enchantment 5 damage 800 G → payout 700 G (full then deductible)");
108	  it.todo("steel sword enchantment 9 damage 1000 G → payout 400 G (50% then deductible)");
109	
110	  // Deductible per damage event
111	  it.todo("dragon attack damages sword 500 + amulet 300 → payout 600 G (deductible per item)");
112	
113	  // Multiple items of same type
114	  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
115	  it.todo("two-sword policy: two sword damages → each treated separately with own deductible");
116	  it.todo("claim with more sword damages than policy covers → CLI error");
117	
118	  // Cap exhaustion
119	  it.todo("sword + amulet → insurance sum 1600 G, cap 3200 G");
120	  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
121	  it.todo("sword + 3 runes (block) → insurance sum 1750 G");
122	  it.todo("sword cap 2000 G: two claims of 1500 G → 1400 G then 600 G");
123	
124	  // Error edge cases
125	  it.todo("quote with unknown item type → CLI error");
126	  it.todo("claim damage references item not in policy → CLI error");
127	  it.todo("claim damage with negative amount → CLI error");
128	});
